template <bool B>
inline bool VerifyEventData(::flatbuffers::VerifierTemplate<B> &verifier, const void *obj, EventData type) {
  switch (type) {
    case EventData::NONE: {
      return true;
    }
    case EventData::GenericFileEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::GenericFileEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::ChownEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::ChownEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::ChmodEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::ChmodEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::ExecEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::ExecEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::ForkEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::ForkEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::ExitEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::ExitEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::RenameEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::RenameEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EventData::NetworkEventData: {
      auto ptr = reinterpret_cast<const owlsm::fb::NetworkEventData *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

template <bool B>
inline bool VerifyEventDataVector(::flatbuffers::VerifierTemplate<B> &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<EventData> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyEventData(
        verifier,  values->Get(i), types->GetEnum<EventData>(i))) {
      return false;
    }
  }
  return true;
}

inline const owlsm::fb::Event *GetEvent(const void *buf) {
  return ::flatbuffers::GetRoot<owlsm::fb::Event>(buf);
}

inline const owlsm::fb::Event *GetSizePrefixedEvent(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<owlsm::fb::Event>(buf);
}

template <bool B = false>
inline bool VerifyEventBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<owlsm::fb::Event>(nullptr);
}

template <bool B = false>
inline bool VerifySizePrefixedEventBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<owlsm::fb::Event>(nullptr);
}

inline void FinishEventBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<owlsm::fb::Event> root) {
  fbb.Finish(root);
}

inline void FinishSizePrefixedEventBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<owlsm::fb::Event> root) {
  fbb.FinishSizePrefixed(root);
}

